    JsonObject jsobj = jsin.get_object();
    jsobj.read( "plant_location", actor.plant_location );
    jsobj.read( "seed_type", actor.seed_type );
    jsobj.read( "plant_duration", actor.plant_duration );
    return actor.clone();
